#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

int main() {
    // CREATE AND OPEN FILE
    int fd = open("test.txt", O_CREAT | O_WRONLY, 0644);

    // WRITE TO FILE
    char buffer[] = "Hello, File System!";
    write(fd, buffer, sizeof(buffer));

    // CLOSE FILE
    close(fd);

    // REOPEN FOR READING
    fd = open("test.txt", O_RDONLY);

    // READ FROM FILE
    char readBuffer[50];
    read(fd, readBuffer, 20);

    // SEEK TO BEGINNING
    lseek(fd, 0, SEEK_SET);

    // CLOSE FILE
    close(fd);
    return 0;
}

import java.io.*;

public class FileDemo {
    public static void main(String[] args) {
        String filename = "sample.txt";

        // WRITE TO FILE (Buffered)
        try (BufferedWriter writer = new BufferedWriter(
                new FileWriter(filename))) {
            writer.write("This is file concept demonstration\n");
            writer.write("Second line of data\n");
            writer.write("Third line with more content\n");
        } catch (IOException e) {
            e.printStackTrace();
        }

        // READ FILE SEQUENTIALLY
        try (BufferedReader reader = new BufferedReader(
                new FileReader(filename))) {
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        // RANDOM ACCESS
        try (RandomAccessFile raf = new RandomAccessFile(filename, "r")) {
            raf.seek(8);  // Jump to byte 8
            System.out.println("From position 8: " + raf.readLine());

            System.out.println("Current position: " + raf.getFilePointer());
            System.out.println("File length: " + raf.length());
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
